}

message GetUserProfileResponse {
  Profile profile = 1;
}

// -------------------------------------------------------
// UpdateProfile (부분 업데이트 - FieldMask 패턴)
// -------------------------------------------------------

message UpdateProfileRequest {
  string user_id = 1;

  // FieldMask: 실제로 업데이트할 필드 경로 목록
  // 예: ["nickname", "bio", "interests"]
  repeated string update_mask = 2;

  // 변경할 값들 (update_mask에 포함된 필드만 적용)
  optional string nickname = 3;
  optional string bio = 4;
  repeated string interests = 5;
  optional string location = 6;
  optional string profile_image_url = 7;
  repeated string additional_image_urls = 8;
}

message UpdateProfileResponse {
  Profile profile = 1;
}
```

### FieldMask 패턴 사용 이유

proto3에서 `optional`만으로는 `"" (빈 문자열)`과 `null (미전달)`을 구분할 수 없습니다. `update_mask`를 함께 전달하여 어떤 필드를 실제로 변경할 것인지 명시적으로 지정합니다. Google API Design Guide 권장 패턴입니다.

예시: `bio`를 빈 문자열로 초기화하려면

```
update_mask = ["bio"]
bio = ""
```

