## 4. GraphQL Controller / Service 구현체

### Controller

파일 위치: `graphql/src/main/kotlin/com/maum/backend/controller/profile/ProfileController.kt`

```kotlin
@Controller
class ProfileController(
    private val profileService: ProfileService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun myProfile(
        @UserId userId: String,
    ): ProfileResponse {
        val response = profileService.getMyProfile(userId)
        return response.profile.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun userProfile(
        @UserId userId: String,
        @Argument userId: String,
    ): ProfileResponse? {
        val response = profileService.getUserProfile(
            requesterUserId = userId,
            targetUserId = userId,
        )
        return response.profile?.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateProfile(
        @UserId userId: String,
        @Argument input: UpdateProfileInput,
    ): UpdateProfilePayload {
        val response = profileService.updateProfile(userId, input)
        return UpdateProfilePayload(profile = response.profile.toResponse())
    }
}
```

### GraphQL Service (gRPC Client)

파일 위치: `graphql/src/main/kotlin/com/maum/backend/service/profile/ProfileService.kt`

```kotlin
@Service
class ProfileService {

    @GrpcClient("profile-grpc")
    private lateinit var stub: ProfileServiceGrpc.ProfileServiceBlockingStub

    fun getMyProfile(userId: String): GetMyProfileResponse {
        val request = GetMyProfileRequest.newBuilder()
            .setUserId(userId)
            .build()
        return try {
            stub.getMyProfile(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun getUserProfile(requesterUserId: String, targetUserId: String): GetUserProfileResponse {
        val request = GetUserProfileRequest.newBuilder()
            .setRequesterUserId(requesterUserId)
            .setTargetUserId(targetUserId)
            .build()
        return try {
            stub.getUserProfile(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun updateProfile(userId: String, input: UpdateProfileInput): UpdateProfileResponse {
        val requestBuilder = UpdateProfileRequest.newBuilder()
            .setUserId(userId)

        // FieldMask 구성: null이 아닌 필드만 update_mask에 추가
        val mask = mutableListOf<String>()

        input.nickname?.let {
            requestBuilder.setNickname(it)
            mask.add("nickname")
        }
        input.bio?.let {
            requestBuilder.setBio(it)
            mask.add("bio")
        }
        input.interests?.let {
            requestBuilder.addAllInterests(it)
            mask.add("interests")
        }
        input.location?.let {
            requestBuilder.setLocation(it)
            mask.add("location")
        }
        input.profileImageUrl?.let {
            requestBuilder.setProfileImageUrl(it)
            mask.add("profile_image_url")
        }
        input.additionalImageUrls?.let {
            requestBuilder.addAllAdditionalImageUrls(it)
            mask.add("additional_image_urls")
        }

        requestBuilder.addAllUpdateMask(mask)

        return try {
            stub.updateProfile(requestBuilder.build())
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
```

